import sys
from kafka.admin import KafkaAdminClient
from kafka.errors import ConfigException

def parse_config():
    from argparse import ArgumentParser
    parser = ArgumentParser(description='Kafka Cluster Admin')
    parser.add_argument('--bootstrap-server', required=True)
    parser.add_argument('--topic-name', nargs='+', help='Topic name(s) for create operation')
    parser.add_argument('--partition-count', type=int, help='Number of partitions to be created')
    parser.add_argument('--replication-factor', type=int, help='Replication factor for the topic')
    args = parser.parse_args()
    
    if not all([args.topic_name]):
        print("Error: Topic name(s) must be provided.")
        sys.exit(1)
        
    config = {}
    config['bootstrap_servers'] = [args.bootstrap_server]
    
    return args, config

def create_topic(admin_client, topic_name, partition_count, replication_factor):
    try:
        result = admin_client.create_topics(
            new_topics=[{
                'topic': topic_name,
                'num_partitions': partition_count,
                'replication_factor': replication_factor
            }],
            validate_only=False
        )
        
        print(f"Topic {topic_name} created successfully.")
        
    except ConfigException as e:
        if str(e) == "Missing required configuration: num.partitions":
            partition_count = 1
        
        result = admin_client.create_topics(
            new_topics=[{
                'topic': topic_name,
                'num_partitions': partition_count,
                'replication_factor': replication_factor
            }],
            validate_only=False
        )
        
        print(f"Topic {topic_name} created successfully.")
    
    except Exception as e:
        print(f"Error creating topic: {str(e)}")
        sys.exit(1)

def main():
    args, config = parse_config()
    
    admin_client = KafkaAdminClient(**config)
    
    for topic in args.topic_name:
        if args.partition_count and args.replication_factor:
            create_topic(admin_client, topic, args.partition_count, args.replication_factor)
        elif args.partition_count and not args.replication_factor:
            create_topic(admin_client, topic, args.partition_count, 1)
        else:
            print(f"Error: You must provide both partition-count or neither.")

if __name__ == "__main__":
    main()